// Get agents and stats data
const agents = $('Get Agents').first().json;
const stats = $('Get Alerts').first().json;

// Agent counts
const conn = agents.data?.connection || {};
const totalAgents = conn.total || 0;
const activeAgents = conn.active || 0;

// Get current hour's alerts from manager stats
const hours = stats.data?.affected_items || [];
const currentHour = new Date().getHours();
// Find the matching hour entry, or use the latest
const hourData = hours.find(h => h.hour === currentHour) || hours[hours.length - 1] || {};
const alerts = hourData.alerts || [];

// Count totals by severity level
// Wazuh levels: 0-3 low, 4-7 medium, 8-11 high, 12+ critical
let totalAlerts = 0, critical = 0, high = 0, medium = 0;
let topRule = { sigid: null, times: 0 };

for (const a of alerts) {
  const times = a.times || 0;
  const level = a.level || 0;
  totalAlerts += times;

  if (level >= 12) critical += times;
  else if (level >= 8) high += times;
  else if (level >= 4) medium += times;

  if (times > topRule.times) {
    topRule = { sigid: a.sigid, times: times };
  }
}

return [{
  json: {
    total_alerts: totalAlerts,
    critical_alerts: critical,
    high_alerts: high,
    medium_alerts: medium,
    agent_count: totalAgents,
    agents_active: activeAgents,
    top_rule_id: topRule.sigid ? String(topRule.sigid) : null,
    top_rule_desc: null,
    raw_json: JSON.stringify({ agents: agents.data, stats: hourData })
  }
}];

const agents = $('Get Agent List').first().json.data.affected_items || [];
return agents.map(a => ({
  json: {
    agent_id: a.id,
    agent_name: a.name,
    platform: a.os?.platform || 'unknown',
    status: a.status || 'unknown'
  }
}));

const agents = $('Split Agents').all();
const responses = $input.all();
const output = [];

for (let i = 0; i < responses.length; i++) {
  const agent = agents[i].json;
  const response = responses[i].json;
  const totalFim = response.data?.total_affected_items || 0;
  const recentFim = response.data?.affected_items?.length || 0;

  output.push({
    json: {
      agent_id: agent.agent_id,
      agent_name: agent.agent_name,
      total_fim_events: totalFim,
      recent_fim_events: recentFim
    }
  });
}

return output;

const agents = $('Split Agents').all();
const responses = $input.all();
const output = [];

for (let i = 0; i < responses.length; i++) {
  const agent = agents[i].json;
  const response = responses[i].json;
  const items = response.data?.affected_items || [];

  const limited = items.slice(0, 100);
  for (const item of limited) {
    output.push({
      json: {
        agent_id: agent.agent_id,
        file_path: item.file || '',
        event_type: item.type || 'file',
        change_count: item.changes || 1,
        file_type: item.type || 'file',
        md5: item.md5 || null,
        sha1: item.sha1 || null,
        sha256: item.sha256 || null,
        size: item.size || 0,
        fim_date: item.date || null
      }
    });
  }
}

return output;

const stats = $('Get Alerts').first().json;
const hours = stats.data?.affected_items || [];
const output = [];

for (const h of hours) {
  const alerts = h.alerts || [];
  let total = 0, highPlus = 0;
  for (const a of alerts) {
    total += a.times || 0;
    if (a.level >= 7) highPlus += a.times || 0;
  }
  output.push({
    json: {
      hour: h.hour,
      total_alerts: total,
      high_plus_alerts: highPlus,
      syscheck_events: h.syscheck || 0,
      firewall_events: h.firewall || 0,
      total_events: h.events || 0
    }
  });
}
return output;

const stats = $('Get Alerts').first().json;
const hours = stats.data?.affected_items || [];
const latest = hours[hours.length - 1] || {};
const alerts = latest.alerts || [];

// Get top 15 rules with level > 0, sorted by count
const top = alerts
  .filter(a => a.level > 0)
  .sort((a, b) => b.times - a.times)
  .slice(0, 15);

const ruleIds = top.map(a => a.sigid).join(',');

return [{
  json: {
    hour: latest.hour || 0,
    top_rules: top,
    rule_ids_param: ruleIds
  }
}];

const topRulesData = $('Extract Top Rules').first().json;
const hour = topRulesData.hour;
const topRules = topRulesData.top_rules;
const rulesResponse = $('Fetch Rule Descriptions').first().json;
const ruleDescs = rulesResponse.data?.affected_items || [];

// Build a map of rule_id -> description/groups
const descMap = {};
for (const r of ruleDescs) {
  descMap[r.id] = {
    description: r.description || '',
    level: r.level || 0,
    groups: (r.groups || []).slice(0, 5).join(',')
  };
}

const output = [];
for (const rule of topRules) {
  const desc = descMap[rule.sigid] || {};
  output.push({
    json: {
      hour: hour,
      rule_id: rule.sigid,
      rule_desc: (desc.description || 'Unknown').replace(/'/g, "''"),
      rule_level: desc.level || rule.level,
      rule_groups: (desc.groups || '').replace(/'/g, "''"),
      hit_count: rule.times
    }
  });
}
return output;

const agents = $('Split Agents').all();
const responses = $input.all();
const output = [];

const criticalPaths = ['/etc/', '/usr/bin/', '/usr/sbin/', '/usr/local/bin/', '/usr/local/sbin/',
  '/boot/', '/root/', '/var/spool/cron', '/var/spool/at',
  'HKEY_LOCAL_MACHINE\\Software\\Microsoft\\Windows\\CurrentVersion\\Run',
  'HKEY_LOCAL_MACHINE\\System\\CurrentControlSet\\Services',
  '/Library/LaunchDaemons/', '/Library/LaunchAgents/'];

for (let i = 0; i < responses.length; i++) {
  const agent = agents[i].json;
  const response = responses[i].json;
  const items = response.data?.affected_items || [];

  for (const item of items) {
    const path = item.file || '';
    const isCritical = criticalPaths.some(cp => path.includes(cp));
    if (isCritical) {
      output.push({
        json: {
          agent_id: agent.agent_id,
          agent_name: agent.agent_name,
          file_path: path.replace(/'/g, "''"),
          change_count: item.changes || 1,
          md5: item.md5 || '',
          sha256: item.sha256 || '',
          size: item.size || 0,
          fim_date: item.date || ''
        }
      });
    }
  }
}

if (output.length === 0) {
  return [{json: {_empty: true}}];
}
return output;
